{
var seed = GetInt(parameters, "seed", context.Seed);
var rustAmount = GetFloat(parameters, "rustAmount", 0.5f);
var scale = GetFloat(parameters, "scale", 3f);
var edgeCorrosion = GetFloat(parameters, "edgeCorrosion", 0.5f);
var corrosionType = GetChoice(parameters, "corrosionType", "ironRust");
var orangeRust = GetColor(parameters, "orangeRust", Color.FromRgb(180, 100, 40));
var brownRust = GetColor(parameters, "brownRust", Color.FromRgb(120, 60, 30));
var patinaColor = GetColor(parameters, "patinaColor", Color.FromRgb(70, 140, 110));
var flakeSize = GetFloat(parameters, "flakeSize", 0.5f);
var pitting = GetFloat(parameters, "pitting", 0.3f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var hasBase = inputs.Length > 0 && inputs[0] != null;
var input = hasBase ? inputs[0]! : null;
var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var oR = orangeRust.R / 255f; var oG = orangeRust.G / 255f; var oB = orangeRust.B / 255f;
var bR = brownRust.R / 255f; var bG = brownRust.G / 255f; var bB = brownRust.B / 255f;
var pR = patinaColor.R / 255f; var pG = patinaColor.G / 255f; var pB = patinaColor.B / 255f;

// Pre-compute edge map for corrosion concentration
var edgeMap = new PixelBuffer(size, size);
if (hasBase && edgeCorrosion > 0f)
{
    edgeMap.ParallelForEachPixel((x, y) =>
    {
        var (cr, cg, cb, _) = input!.GetPixel(x, y);
        var (lr, lg, lb, _) = input.GetPixel(Math.Max(0, x - 1), y);
        var (rr, rg, rb, _) = input.GetPixel(Math.Min(size - 1, x + 1), y);

        var cLum = cr * 0.299f + cg * 0.587f + cb * 0.114f;
        var lLum = lr * 0.299f + lg * 0.587f + lb * 0.114f;
        var rLum = rr * 0.299f + rg * 0.587f + rb * 0.114f;

        var edge = MathF.Abs(cLum - lLum) + MathF.Abs(cLum - rLum);
        edgeMap.SetPixel(x, y, Math.Clamp(edge * 2f, 0f, 1f), 0, 0, 1f);
    });
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Multi-frequency rust noise
    var largeRust = TileableFractalNoise(u * scale * 0.5f, v * scale * 0.5f, Math.Max(1, (int)MathF.Round(scale * 0.5f)), 3, 0.6f, 2f, seed);
    var smallRust = TileableFractalNoise(u * scale * 2f, v * scale * 2f + 50f, Math.Max(1, (int)MathF.Round(scale * 2f)), 2, 0.5f, 2f, seed + 100);
    var pitNoise = TileableFractalNoise(u * scale * 4f, v * scale * 4f + 100f, Math.Max(1, (int)MathF.Round(scale * 4f)), 2, 0.4f, 2f, seed + 200);

    // Edge corrosion amplification
    var edgeFactor = 0f;
    if (hasBase && edgeCorrosion > 0f)
    {
        var (e, _, _, _) = edgeMap.GetPixel(x, y);
        edgeFactor = e * edgeCorrosion;
    }

    // Combine rust signals
    var rustSignal = largeRust * 0.6f + smallRust * 0.3f + pitNoise * pitting * 0.2f + edgeFactor * 0.3f;
    rustSignal = Math.Clamp(rustSignal, 0f, 1f);

    // Threshold to create rust patches
    var threshold = 1f - rustAmount;
    var hasRust = rustSignal > threshold;

    // Determine rust colors based on corrosion type
    float r1R, r1G, r1B, r2R, r2G, r2B;
    switch (corrosionType)
    {
        case "patina":
            r1R = pR; r1G = pG; r1B = pB;
            r2R = pR * 0.7f; r2G = pG * 1.2f; r2B = pB * 0.8f;
            break;
        case "mixed":
            // Mix iron rust and copper patina based on noise
            var mixFactor = TileableFractalNoise(u * scale + 300f, v * scale + 300f, Math.Max(1, (int)MathF.Round(scale)), 2, 0.5f, 2f, seed + 500);
            r1R = Lerp(oR, pR, mixFactor);
            r1G = Lerp(oG, pG, mixFactor);
            r1B = Lerp(oB, pB, mixFactor);
            r2R = Lerp(bR, pR * 0.7f, mixFactor);
            r2G = Lerp(bG, pG * 1.2f, mixFactor);
            r2B = Lerp(bB, pB * 0.8f, mixFactor);
            break;
        default: // ironRust
            r1R = oR; r1G = oG; r1B = oB;
            r2R = bR; r2G = bG; r2B = bB;
            break;
    }

    float r, g, b;
    if (hasRust && hasBase)
    {
        // Blend rust over base surface
        var rustIntensity = (rustSignal - threshold) / (1f - threshold);
        var (br, bg, bb, _) = input!.GetPixel(x, y);

        // Mix bright and dark rust based on rust intensity
        var rustR = Lerp(r2R, r1R, rustIntensity);
        var rustG = Lerp(r2G, r1G, rustIntensity);
        var rustB = Lerp(r2B, r1B, rustIntensity);

        // Pitting darkens rust
        var pitDarken = 1f - pitNoise * pitting * 0.5f;

        r = Lerp(br, rustR * pitDarken, rustIntensity);
        g = Lerp(bg, rustG * pitDarken, rustIntensity);
        b = Lerp(bb, rustB * pitDarken, rustIntensity);
    }
    else if (hasRust)
    {
        // Pure rust (no base)
        var rustIntensity = (rustSignal - threshold) / (1f - threshold);
        var rustR = Lerp(r2R, r1R, rustIntensity);
        var rustG = Lerp(r2G, r1G, rustIntensity);
        var rustB = Lerp(r2B, r1B, rustIntensity);
        var pitDarken = 1f - pitNoise * pitting * 0.5f;

        r = rustR * pitDarken;
        g = rustG * pitDarken;
        b = rustB * pitDarken;
    }
    else if (hasBase)
    {
        // No rust — show base surface
        var (br, bg, bb, _) = input!.GetPixel(x, y);
        r = br; g = bg; b = bb;
    }
    else
    {
        // Default gray metal
        var metal = 0.6f + (largeRust - 0.5f) * 0.2f;
        r = metal; g = metal; b = metal;
    }

    // Flaking: dark spots
    if (flakeSize > 0f)
    {
        var flakeNoise = TileableFractalNoise(u * scale * 3f + 200f, v * scale * 3f + 200f, Math.Max(1, (int)MathF.Round(scale * 3f)), 1, 0.5f, 2f, seed + 300);
        if (flakeNoise > 1f - flakeSize * 0.5f)
        {
            var flakeDark = (flakeNoise - (1f - flakeSize * 0.5f)) / (flakeSize * 0.5f);
            r *= 1f - flakeDark * 0.4f;
            g *= 1f - flakeDark * 0.5f;
            b *= 1f - flakeDark * 0.4f;
        }
    }

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
